<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***BulkUpdateAPIEndpoint*ForsafedatabaseupdatefromCSV*/require_once__DIR__.'/../core/config.php';header("Content-Type:application/json");/Enableerrorreportingerror_reporting(E_ALL);ini_set("display_errors",1);try{/Connecttodatabase$pdo=newPDO("mysql:host=".DB_HOST.";dbname=".DB_NAME,DB_USER,DB_PASS);$pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);/Getmethod$method=$_SERVER["REQUEST_METHOD"];if($method==="POST"){/GetJSONdata$json_data=file_get_contents("php://input");$personil_data=json_decode($json_data,true);if(!$personil_data||!isset($personil_data["personil"])){thrownewException("Invaliddataformat");}/Starttransaction$pdo->beginTransaction();try{/Clearexistingdata$pdo->exec("DELETEFROMpersonil");/Getreferencedata$pangkat_stmt=$pdo->query("SELECTid,nama_pangkatFROMpangkat");$pangkat_ref=[];while($row=$pangkat_stmt->fetch(PDO::FETCH_ASSOC)){$pangkat_ref[strtoupper($row["nama_pangkat"])]=$row["id"];}$jabatan_stmt=$pdo->query("SELECTid,nama_jabatanFROMjabatan");$jabatan_ref=[];while($row=$jabatan_stmt->fetch(PDO::FETCH_ASSOC)){$jabatan_ref[strtoupper($row["nama_jabatan"])]=$row["id"];}$bagian_stmt=$pdo->query("SELECTid,nama_bagianFROMbagian");$bagian_ref=[];while($row=$bagian_stmt->fetch(PDO::FETCH_ASSOC)){$bagian_ref[strtoupper($row["nama_bagian"])]=$row["id"];}/Insertnewdata$insert_count=0;$error_count=0;forforeach($personil_data["personil"]as$personil){$db_data=["nama"=>$personil["nama"]??"","nrp"=>$personil["nrp"]??"","status_ket"=>$personil["status_ket"]??"aktif","status_kepegawaian"=>$personil["status_kepegawaian"]??"POLRI"];/Mapreferencesif(!empty($personil["pangkat"])){$pangkat_key=strtoupper(trim($personil["pangkat"]));$db_data["pangkat_id"]=$pangkat_ref[$pangkat_key]??null;}if(!empty($personil["jabatan"])){$jabatan_key=strtoupper(trim($personil["jabatan"]));$db_data["jabatan_id"]=$jabatan_ref[$jabatan_key]??null;}if(!empty($personil["bagian"])){$bagian_key=strtoupper(trim($personil["bagian"]));$db_data["bagian_id"]=$bagian_ref[$bagian_key]??null;}/Insert$sql="INSERTINTOpersonil(nama,nrp,pangkat_id,jabatan_id,bagian_id,status_ket,status_kepegawaian)VALUES(:nama,:nrp,:pangkat_id,:jabatan_id,:bagian_id,:status_ket,:status_kepegawaian)";$stmt=$pdo->prepare($sql);/Handlenullvaluesforforeignkeysif(empty($db_data["pangkat_id"]))$db_data["pangkat_id"]=null;if(empty($db_data["jabatan_id"]))$db_data["jabatan_id"]=null;if(empty($db_data["bagian_id"]))$db_data["bagian_id"]=null;$stmt->execute($db_data);$insert_count++;}/Committransaction$pdo->commit();echojson_encode(["success"=>true,"message"=>"Bulkupdatecompleted","inserted"=>$insert_count,"errors"=>$error_count]);}catch(Exception$e){$pdo->rollBack();throw$e;}}else{/GETmethod-showcurrentstatus$stmt=$pdo->query("SELECTCOUNT(*)astotalFROMpersonil");$count=$stmt->fetch()["total"];echojson_encode(["success"=>true,"message"=>"BulkupdateAPIready","current_count"=>$count,"method"=>"POSTtoupdatedata"]);}}catch(Exception$e){http_response_code(500);echojson_encode(["success"=>false,"error"=>$e->getMessage()]);}?>
